int bpf_map_update_elem(
int map_fd,         // FD from bpf_obj_get()
const void *key,    // &key (u32 = 0)
const void *value,  // &cfg (filter_config)
__u64 flags         // BPF_ANY
);

c
// In handle_tcp_state_change()
__u32 key = 0;
struct filter_config *cfg;
cfg = bpf_map_lookup_elem(&config, &key);
if (!cfg) {
// Use defaults
return trace_all;
}

if (!cfg->enabled)
return true;  // Trace all
if (cfg->filter_pid != 0 &&
pid != cfg->filter_pid)
return false;
if (cfg->filter_dport != 0 &&
dport != cfg->filter_dport)
return false;
// IP prefix matching...
return true;
